exercises.solution_code:
#include <iostream>
#include <string>

enum Light
{
    red = 0,
    yellow = 1,
    green = 2
};

std::string lightName(Light l)
{
    switch (l)
    {
        case red:    return "red";
        case yellow: return "yellow";
        case green:  return "green";
        default:     return "unknown";
    }
}

Light nextLight(Light current)
{
    switch (current)
    {
        case red:    return green;
        case green:  return yellow;
        case yellow: return red;
        default:     return red;
    }
}

int main()
{
    int input{};
    std::cin >> input;

    Light current{ static_cast<Light>(input) };
    std::cout << lightName(current) << '\n';
    std::cout << lightName(nextLight(current)) << '\n';

    return 0;
}

