exercises.solution_code:
#include <iostream>
#include <string>

enum Day
{
    Sunday = 0,
    Monday = 1,
    Tuesday = 2,
    Wednesday = 3,
    Thursday = 4,
    Friday = 5,
    Saturday = 6
};

std::string dayName(Day d)
{
    switch (d)
    {
        case Sunday:    return "Sunday";
        case Monday:    return "Monday";
        case Tuesday:   return "Tuesday";
        case Wednesday: return "Wednesday";
        case Thursday:  return "Thursday";
        case Friday:    return "Friday";
        case Saturday:  return "Saturday";
        default:        return "Unknown";
    }
}

int main()
{
    int startDay{};
    int offset{};
    std::cin >> startDay >> offset;

    Day start{ static_cast<Day>(startDay) };
    Day future{ static_cast<Day>((start + offset) % 7) };

    std::cout << dayName(start) << '\n';
    std::cout << dayName(future) << '\n';

    return 0;
}
